import json
import os
import sys
import time
from pathlib import Path

HOOKS_DIR = str(Path(__file__).parent.parent.parent.parent / "hooks")
sys.path.insert(0, HOOKS_DIR)
from lib.allowlist import consume_sentinel_grant_on_terminal_result, SENTINEL_GRANT_DIR

AC_UID = "ac3-posttool-consumes-write-sentinel"
AC_TYPE = "hook"


def _write_sentinel(task_id, session_id, ops, ttl=300):
    os.makedirs(SENTINEL_GRANT_DIR, exist_ok=True)
    path = os.path.join(SENTINEL_GRANT_DIR, f"{task_id}.json")
    now = time.time()
    grant = {"task_id": task_id, "session_id": session_id,
             "allowed_operations": ops, "created_at": now, "expires_at": now + ttl}
    with open(path, "w") as f:
        json.dump(grant, f)
    return path


def test_AC3():
    """
    GIVEN: a valid sentinel with {"op":"Write","target":"/tmp/allowed.json"} and posttool-allowlist-consume.py receives Write PostToolUse event with tool_input.file_path=="/tmp/allowed.json"
    WHEN:  posttool-allowlist-consume.py main() runs
    THEN:  consume_sentinel_grant_on_terminal_result is called and the sentinel file at /tmp/claude-grants/<task_id>.json is unlinked
    """
    task_id, session_id = "gen-ac3-posttool-consume", "gen-ac3-session"
    path = _write_sentinel(task_id, session_id, [{"op": "Write", "target": "/tmp/allowed.json"}])
    assert os.path.exists(path), "Sentinel file must exist before consume"
    try:
        consumed = consume_sentinel_grant_on_terminal_result(task_id, "success")
        assert consumed is True, "consume should return True when sentinel file was unlinked"
        assert not os.path.exists(path), "Sentinel file must be unlinked after consume"
    finally:
        if os.path.exists(path):
            os.unlink(path)
